mapper.select:
SELECT t.*
FROM task t


        AND EXISTS (
            SELECT 1 FROM task_assignee ta
            WHERE ta.task_id = t.id AND ta.assignee_id = #{assigneeId}
        )


        AND t.status = #{status}


        AND t.creator_id = #{creatorId}


        AND t.mode = #{mode}


        AND (t.title LIKE CONCAT('%', #{keyword}, '%')
          OR t.content LIKE CONCAT('%', #{keyword}, '%'))


ORDER BY t.created_at DESC
